def gen(rng, size):
    n = max(3, min(size, 50))
    seen = set()
    pts = []
    while len(pts) < n:
        p = (rng.randint(-50, 50), rng.randint(-50, 50))
        if p not in seen:
            seen.add(p)
            pts.append([p[0], p[1]])
    return [pts]

