class Solution:
    def largestTriangleArea(self, points):
        import itertools
        best = 0.0
        for a, b, c in itertools.combinations(points, 3):
            # Heron-free: shoelace.
            area = abs(a[0] * (b[1] - c[1]) + b[0] * (c[1] - a[1]) + c[0] * (a[1] - b[1])) / 2.0
            if area > best:
                best = area
        return best

